import anthropic, json

client = anthropic.Anthropic()

HANDOFF_TOOL = {
    "name": "generate_handoff_package",
    "description": "Produce a structured handoff package from behaviour spec and eval results",
    "input_schema": {
        "type": "object",
        "required": ["behaviour_spec", "eval_results", "failure_modes"],
        "properties": {
            "behaviour_spec": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["id", "type", "statement", "test_signal"],
                    "properties": {
                        "id": {"type": "string"},
                        "type": {"enum": ["must_do", "must_not_do"]},
                        "statement": {"type": "string"},
                        "test_signal": {"type": "string"}
                    }
                }
            },
            "eval_results": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["spec_id", "pass_rate", "sample_inputs", "status"],
                    "properties": {
                        "spec_id": {"type": "string"},
                        "pass_rate": {"type": "number"},
                        "sample_inputs": {"type": "array", "items": {"type": "string"}},
                        "status": {"enum": ["PASS", "FAIL", "NEEDS_REVIEW"]}
                    }
                }
            },
            "failure_modes": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["id", "description", "severity", "rpn", "mitigation"],
                    "properties": {
                        "id": {"type": "string"},
                        "description": {"type": "string"},
                        "severity": {"type": "integer", "minimum": 1, "maximum": 10},
                        "rpn": {"type": "integer"},
                        "mitigation": {"type": "string"}
                    }
                }
            }
        }
    }
}

def generate_handoff_package(behaviour_spec, eval_results, failure_modes):
    spec_json = json.dumps(behaviour_spec, indent=2)
    eval_json = json.dumps(eval_results, indent=2)
    fm_json = json.dumps(failure_modes, indent=2)

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=4096,
        tools=[HANDOFF_TOOL],
        tool_choice={"type": "tool", "name": "generate_handoff_package"},
        messages=[{
            "role": "user",
            "content": (
                f"Generate a complete handoff package from this prototype work.\n\n"
                f"Behaviour spec:\n{spec_json}\n\n"
                f"Eval results:\n{eval_json}\n\n"
                f"Failure modes:\n{fm_json}\n\n"
                "Populate all five package components. For eval_results with "
                "status=FAIL, mark the corresponding spec items as BLOCKED in the "
                "handoff and note that prototype rework is required before build."
            )
        }]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

MATRIX_TOOL = {
    "name": "build_traceability_matrix",
    "description": "Link requirements to prototypes, evals, and tickets in a traceability matrix",
    "input_schema": {
        "type": "object",
        "required": ["rows"],
        "properties": {
            "rows": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["req_id", "req_summary", "proto_ids",
                                 "eval_ids", "eval_status", "ticket_id", "ticket_status"],
                    "properties": {
                        "req_id": {"type": "string"},
                        "req_summary": {"type": "string"},
                        "proto_ids": {"type": "array", "items": {"type": "string"}},
                        "eval_ids": {"type": "array", "items": {"type": "string"}},
                        "eval_status": {"enum": ["PASS", "FAIL", "NEEDS_REVIEW"]},
                        "ticket_id": {"type": "string"},
                        "ticket_status": {
                            "enum": ["READY", "BLOCKED", "IN_PROGRESS", "DONE"]
                        },
                        "notes": {"type": "string"}
                    }
                }
            },
            "blocked_count": {"type": "integer"},
            "ready_count": {"type": "integer"},
            "coverage_pct": {"type": "number"}
        }
    }
}

def build_traceability_matrix(requirements, prototypes, eval_results):
    """
    requirements: list of {id, summary}
    prototypes:   list of {id, req_ids, outcome}
    eval_results: list of {id, proto_id, pass_rate, threshold, status}
    """
    context = json.dumps({
        "requirements": requirements,
        "prototypes": prototypes,
        "eval_results": eval_results
    }, indent=2)

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2048,
        tools=[MATRIX_TOOL],
        tool_choice={"type": "tool", "name": "build_traceability_matrix"},
        messages=[{
            "role": "user",
            "content": (
                f"Build a traceability matrix from this prototype evidence:\n{context}\n\n"
                "Rules:\n"
                "- ticket_status=BLOCKED when any linked eval has status=FAIL\n"
                "- ticket_status=READY when all linked evals PASS\n"
                "- coverage_pct = (requirements with ≥1 PASS eval) / total requirements * 100"
            )
        }]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

AC_TOOL = {
    "name": "derive_acceptance_criteria",
    "description": "Produce a set of acceptance criteria for a build ticket from prototype evidence",
    "input_schema": {
        "type": "object",
        "required": ["ticket_id", "requirement", "acceptance_criteria"],
        "properties": {
            "ticket_id": {"type": "string"},
            "requirement": {"type": "string"},
            "acceptance_criteria": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["id", "given", "when", "then", "measurement", "threshold", "evidence_ref"],
                    "properties": {
                        "id": {"type": "string"},
                        "given": {"type": "string"},
                        "when": {"type": "string"},
                        "then": {"type": "string"},
                        "measurement": {"type": "string"},
                        "threshold": {"type": "string"},
                        "evidence_ref": {"type": "string"}
                    }
                }
            }
        }
    }
}

def derive_acceptance_criteria(ticket_id, requirement, proto_script, eval_result):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2048,
        tools=[AC_TOOL],
        tool_choice={"type": "tool", "name": "derive_acceptance_criteria"},
        messages=[{
            "role": "user",
            "content": (
                f"Derive acceptance criteria for ticket {ticket_id}\n\n"
                f"Requirement: {requirement}\n\n"
                f"Prototype script excerpt:\n{proto_script}\n\n"
                f"Eval result: {json.dumps(eval_result)}\n\n"
                "Write Given/When/Then criteria with quantitative thresholds "
                "drawn from the eval data. Each criterion must reference the "
                "eval result that validates it (evidence_ref = eval ID)."
            )
        }]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")


# Example usage
result = derive_acceptance_criteria(
    ticket_id="TICKET-101",
    requirement="Escalate to human agent when model confidence falls below 0.6",
    proto_script="""SYSTEM: You are a support assistant. Escalate when unsure.
USER: My order hasn't arrived and it's been three weeks and nobody is helping me.
CLAUDE: [confidence=0.59] I can see this is urgent. Let me connect you with a
        specialist who can check your order status directly. [ESCALATION]
ANNOTATION: confidence gate triggered correctly""",
    eval_result={
        "id": "EVAL-001",
        "pass_rate": 0.94,
        "threshold": 0.90,
        "status": "PASS",
        "sample_size": 100
    }
)
print(json.dumps(result, indent=2))

import anthropic, json

client = anthropic.Anthropic()

TICKET_TOOL = {
    "name": "format_github_issue",
    "description": "Format a GitHub issue body with prototype evidence attached",
    "input_schema": {
        "type": "object",
        "required": ["title", "body_markdown"],
        "properties": {
            "title": {"type": "string"},
            "body_markdown": {"type": "string"},
            "labels": {"type": "array", "items": {"type": "string"}},
            "milestone": {"type": "string"}
        }
    }
}

def format_github_issue(ticket, acceptance_criteria, proto_script, eval_summary):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2048,
        tools=[TICKET_TOOL],
        tool_choice={"type": "tool", "name": "format_github_issue"},
        messages=[{
            "role": "user",
            "content": (
                f"Format a GitHub issue for:\n{json.dumps(ticket)}\n\n"
                f"Acceptance criteria:\n{json.dumps(acceptance_criteria, indent=2)}\n\n"
                f"Prototype script:\n{proto_script}\n\n"
                f"Eval summary:\n{json.dumps(eval_summary)}\n\n"
                "Structure the body as:\n"
                "## Summary\n"
                "## Acceptance Criteria (Given/When/Then)\n"
                "## Prototype Evidence (quoted script excerpt + eval stats)\n"
                "## Failure Modes to Guard Against\n"
                "## Definition of Done"
            )
        }]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

