    "input_schema": {
        "type": "object",
        "required": ["summary", "description_adf", "acceptance_criteria_text",
                     "story_points", "labels"],
        "properties": {
            "summary": {"type": "string"},
            "description_adf": {"type": "object"},
            "acceptance_criteria_text": {"type": "string"},
            "story_points": {"type": "integer"},
            "labels": {"type": "array", "items": {"type": "string"}},
            "linked_req_id": {"type": "string"},
            "linked_proto_ids": {"type": "array", "items": {"type": "string"}},
            "linked_eval_ids": {"type": "array", "items": {"type": "string"}}
        }
