}

def format_jira_ticket(ticket_data, acceptance_criteria, proto_ids, eval_ids):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=2048,
        tools=[JIRA_TOOL],
        tool_choice={"type": "tool", "name": "format_jira_ticket"},
        messages=[{
            "role": "user",
            "content": (
                f"Format a Jira ticket for:\n{json.dumps(ticket_data)}\n\n"
                f"Acceptance criteria:\n{json.dumps(acceptance_criteria, indent=2)}\n\n"
                f"Prototype IDs to link: {proto_ids}\n"
                f"Eval IDs to link: {eval_ids}\n\n"
                "Estimate story points from the acceptance criteria complexity. "
                "Add label 'has-prototype-evidence' and 'ai-feature'."
            )
        }]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")
